/**
 * Confirms many staged-payment matches at once — the bulk equivalent of
POST /staged-payments/{id}/confirm-match, used to clear the Auto-matched
queue in a single action. Each id is confirmed only if it is in a
confirmable state (a pending row with a donor, or an auto-applied approved
row); ids that are missing, already confirmed, or otherwise not
confirmable are silently skipped rather than failing the whole batch. Does
not change donors or mint gifts. The response reports which ids were
confirmed so the client can report partial results.

 * @summary Bulk-confirm several auto-applied/suggested donor matches in one call.
 */



export const ConfirmStagedPaymentMatchesBody = zod.object({
  "ids": zod.array(zod.string()).min(1).describe('Ids of the staged payments to confirm. Ids that are not in a confirmable state are skipped, not errors.')
}).describe('Bulk-confirm several staged-payment matches (e.g. the whole Auto-matched queue) in one call.')

export const ConfirmStagedPaymentMatchesResponse = zod.object({
  "confirmedIds": zod.array(zod.string()).describe('Ids that were actually confirmed.'),
  "requested": zod.number().describe('How many ids were submitted. (requested − confirmedIds.length = skipped.)')
})

/**
 * Reverts many staged-payment matches at once — the bulk equivalent of
POST /staged-payments/{id}/revert, used to clear auto-applied matches off
the Auto-matched queue in a single action. Each id is reverted only if it
is in a revertible state (a match_proposed/match_confirmed row that was
tied to an existing gift, auto-minted, multi-matched, or split); the auto-minted
gift is deleted, pre-existing gifts are untouched. Ids that are missing or
not revertible (e.g. a manually-created gift) are silently skipped rather
than failing the whole batch. The response reports which ids were reverted
so the client can report partial results.

 * @summary Bulk-revert several auto-applied matches in one call.
 */



export const RevertStagedPaymentMatchesBody = zod.object({
  "ids": zod.array(zod.string()).min(1).describe('Ids of the staged payments to revert. Ids that are not in a revertible state are skipped, not errors.')
}).describe('Bulk-revert several auto-applied staged-payment matches (e.g. the whole Auto-matched queue) in one call.')

export const RevertStagedPaymentMatchesResponse = zod.object({
  "revertedIds": zod.array(zod.string()).describe('Ids that were actually reverted.'),
  "requested": zod.number().describe('How many ids were submitted. (requested − revertedIds.length = skipped.)')
})

